create table dirkspzm32.isi_komm_client_platz (
    komm_client_name           varchar2(20 char) not null enable,
    isi_komm_client_platz_name varchar2(20 char) not null enable,
    isi_komm_client_platz_typ  varchar2(1 char),
    lte_id                     varchar2(20 char),
    komm_id                    number(*, 0),
    vorgang_id                 number(*, 0),
    transport_einheit          varchar2(10 char) default 'LTE',
    status                     varchar2(20 char)
);

alter table dirkspzm32.isi_komm_client_platz
    add constraint pk_isi_komm_client_platz primary key ( komm_client_name,
                                                          isi_komm_client_platz_name )
        using index enable;

alter table dirkspzm32.isi_komm_client_platz add constraint uk_isi_komm_client_platz_name unique ( isi_komm_client_platz_name )
    using index enable;


